trait Summary {
    fn summarize(&self) -> String;
}

struct NewsArticle {
    headline: String,
    content: String,
}

impl Summary for NewsArticle {
    fn summarize(&self) -> String {
        format!("{}: {}", self.headline, &self.content[..20])
    }
}

fn create_article() -> impl Summary {
    NewsArticle {
        headline: String::from("Breaking News"),
        content: String::from("Something amazing happened today in the world of Rust..."),
    }
}

fn main() {
    let article = create_article();
    println!("{}", article.summarize());
}
